#include <algorithm>
#include <iostream>
#include <vector>

int main()
{
    int n{};
    std::cin >> n;

    std::vector<int> data(n);
    for (int i{ 0 }; i < n; ++i)
        std::cin >> data[i];

    int threshold{};
    std::cin >> threshold;

    auto isAbove{ [threshold](int val) { return val > threshold; } };

    int count{ static_cast<int>(std::count_if(data.begin(), data.end(), isAbove)) };

    std::vector<int> filtered{};
    std::copy_if(data.begin(), data.end(), std::back_inserter(filtered), isAbove);

    std::sort(filtered.begin(), filtered.end(),
        [](int a, int b) { return a > b; });

    std::cout << "Count: " << count << '\n';
    std::cout << "Filtered:";
    for (int val : filtered)
        std::cout << ' ' << val;
    std::cout << '\n';

    return 0;
}

