#include <iostream>
#include <string>
#include <vector>

int add(int a, int b) { return a + b; }
int multiply(int a, int b) { return a * b; }

int reduce(const int* arr, int size, int (*op)(int, int))
{
    if (size == 1)
        return arr[0];
    return op(arr[0], reduce(arr + 1, size - 1, op));
}

int main()
{
    std::string opName{};
    std::cin >> opName;

    int n{};
    std::cin >> n;

    std::vector<int> data(n);
    for (int i{ 0 }; i < n; ++i)
        std::cin >> data[i];

    int (*opPtr)(int, int){ &add };
    if (opName == "product")
        opPtr = &multiply;

    int result{ reduce(data.data(), n, opPtr) };
    std::cout << "Result: " << result << '\n';

    return 0;
}
